    '      renderGuardrailCard(els.guardrailContext, state.context ? "pass" : state.selected ? "fail" : "neutral", state.context ? "Evidence is loaded" : state.selected ? "Evidence is still loading" : "Evidence not loaded", state.context ? "Evidence and review history are visible for this report." : state.selected ? "Wait for the evidence load before approving or rejecting this report." : "Select a report to inspect evidence.");',
