    '        const result = await request(`/internal/reports/${state.selected.reportId}/review`, { method: "POST", headers: { "content-type": "application/json", ...authHeaders() }, body: JSON.stringify(payload) });',
    '        const reviewedItem = { ...selectedItem, repository: result && result.draft && result.draft.repository ? result.draft.repository : selectedItem.repository, assignedReviewerId: result && result.review && result.review.reviewerId ? result.review.reviewerId : selectedItem.assignedReviewerId, reviewStatus: result && result.review && result.review.status ? result.review.status : status, draftState: result && result.draft && result.draft.state ? result.draft.state : (status === "approved" ? "local-draft" : "rejected"), issueUrl: result && result.draft && result.draft.issueUrl ? result.draft.issueUrl : null, issueNumber: result && result.draft && result.draft.issueNumber ? result.draft.issueNumber : null, syncError: result && result.syncError ? result.syncError : null, reviewedAt: result && result.review && result.review.reviewedAt ? result.review.reviewedAt : new Date().toISOString() };',
    '        state.lastDecision = { reportId: reviewedItem.reportId, repository: reviewedItem.repository, reviewStatus: reviewedItem.reviewStatus, draftState: reviewedItem.draftState, issueUrl: reviewedItem.issueUrl, reviewedAt: reviewedItem.reviewedAt, syncError: reviewedItem.syncError, message: status === "approved" ? (reviewedItem.issueUrl ? "GitHub draft created and the item moved out of the pending queue." : "Approval recorded. The item moved out of the pending queue.") : "Rejection recorded. The item moved out of the pending queue." };',
